INSERT INTO "pr_packages" ("id","number","name","description","teams_involved","requirements","goals","components_list","timeline","expenses","status","created_by","created_at","updated_at","used_in_brand_id") VALUES('prp_dd76d8c14d2643b0',1,'Trust Focus','Створення та ведення сторінок на Trustpilot на дзеркальні домени — від налаштування профілів до регулярної модерації, роботи з відгуками та підтримки стабільного рейтингу.','PR, Retention, Copy','Посилання для сторінок + зациклені мейли для кампаній + бот/сапорт для прийому скрінів',replace('1. Зайняти позиції у пошуковій видачі та не допустити появи "паразитних" або некерованих сторінок із низькими рейтингами.\n2. Побудувати контрольовану репутацію на платформі\n3. Утримувати рейтинг 4.6+, що формує довіру нових користувачів.\n4. Уникати накопичення органічного негативу, який з''являється при відсутності комунікації та модерації з боку бренду.','\n',char(10)),replace('+ Створення та налаштування трьох сторінок бренду на Trustpilot.\n+ Оформлення профілів: основна інформація, логотипи, контактні дані, базові описи.\n+ Регулярна модерація відгуків та оперативні відповіді за узгодженим Tone of Voice.\n+ Виявлення та опрацювання некоректних або фейкових відгуків через Trustpilot dispute-центр.\n+ Постійний моніторинг репутаційної динаміки та ключових показників.\n+ Проведення кампаній для підтримки стабільного рейтингу 4.6+ (e-mail, soft-push, інші інструменти).\n+ Передача критичних або продуктово важливих звернень у Support/Product для опрацювання.\n+ Щомісячна аналітика: рейтинг, кількість відгуків, баланс позитив/негатив, ризики, рекомендації.\n+ Підтримка повної працездатності та актуальності всіх сторінок у довгостроковій перспективі.\n','\n',char(10)),'0-3 місяці протягом повного старту проєкту','Підключення до медіамоніторингу','active','usr_admin_001','2026-02-24 19:09:36','2026-05-20 22:57:30','brand_2118b6523db94282');
INSERT INTO "pr_packages" ("id","number","name","description","teams_involved","requirements","goals","components_list","timeline","expenses","status","created_by","created_at","updated_at","used_in_brand_id") VALUES('prp_d4dbe0d7f7b14e7e',2,'Social Trust','Створення та підтримка активної присутності бренду в соціальних мережах — від розробки контент-стратегії до щоденного постингу та взаємодії з аудиторією.','SMM, Copy, Design','Доступи до соціальних мереж + брендбук + контент-план',replace('1. Забезпечити регулярну присутність бренду в соціальних мережах.\n2. Побудувати довіру через органічний контент та взаємодію з аудиторією.\n3. Створити позитивний імідж бренду через соціальні платформи.\n4. Підвищити впізнаваність та залученість цільової аудиторії.','\n',char(10)),replace('+ Розробка контент-стратегії для основних соціальних платформ.\n+ Створення та публікація регулярних постів згідно з контент-планом.\n+ Дизайн візуального контенту: банери, сторіз, відео-превʼю.\n+ Моніторинг коментарів та оперативні відповіді користувачам.\n+ Аналіз метрик залученості та коригування стратегії.\n+ Координація з іншими командами для актуального контенту.\n+ Проведення спеціальних кампаній та активностей в соцмережах.\n+ Щомісячна звітність з рекомендаціями щодо оптимізації.','\n',char(10)),'1-2 місяці для повного запуску','Рекламний бюджет для просування контенту','active','usr_admin_001','2026-02-24 19:16:47','2026-03-16 16:25:08',NULL);
INSERT INTO "pr_packages" ("id","number","name","description","teams_involved","requirements","goals","components_list","timeline","expenses","status","created_by","created_at","updated_at","used_in_brand_id") VALUES('prp_e4a3cfe1140844d0',3,'Full Reputation','Робота з ключовими оглядачами та рейтинговими платформами — від встановлення контакту до підтримки високих позицій у рейтингах та моніторингу згадок.','PR, Copy, Makeberry Aff','Список цільових оглядачів + матеріали для презентації бренду',replace('1. Забезпечити присутність бренду на провідних оглядових платформах.\n2. Підтримувати високі позиції в рейтингах та топах.\n3. Контролювати інформацію про бренд на оглядових ресурсах.\n4. Оперативно реагувати на зміни рейтингів та згадок бренду.','\n',char(10)),replace('+ Аналіз та формування списку ключових оглядачів у ніші.\n+ Встановлення контакту з представниками оглядових платформ.\n+ Підготовка матеріалів для презентації бренду оглядачам.\n+ Моніторинг позицій бренду на оглядових ресурсах.\n+ Робота над підтримкою високих рейтингів та позицій у топах.\n+ Опрацювання негативних згадок або неточностей в інформації.\n+ Регулярна комунікація з оглядачами для актуалізації даних.\n+ Щомісячна звітність з аналізом позицій та рекомендаціями.','\n',char(10)),'2-4 місяці для повного запуску','Бюджет на співпрацю з оглядачами','active','usr_admin_001','2026-02-24 19:19:53','2026-03-16 16:25:29',NULL);
INSERT INTO "pr_packages" ("id","number","name","description","teams_involved","requirements","goals","components_list","timeline","expenses","status","created_by","created_at","updated_at","used_in_brand_id") VALUES('prp_2a99bf0907b94318',4,'Media Reputation','Побудова медійної присутності бренду через прес-релізи, публікації у профільних виданнях та формування позитивного інформаційного поля навколо продукту.','PR, Copy, Retention','Прес-кіт бренду + контакти медіа + інформаційні приводи',replace('1. Забезпечити регулярну появу бренду у профільних медіа.\n2. Сформувати позитивний інформаційний фон навколо продукту.\n3. Побудувати репутацію бренду як надійного гравця ринку.\n4. Залучити увагу цільової аудиторії через медійні канали.','\n',char(10)),replace('+ Формування медіа-списку профільних видань та журналістів.\n+ Підготовка прес-релізів про ключові події компанії.\n+ Координація інтервʼю та коментарів для медіа.\n+ Моніторинг згадок бренду в медійному просторі.\n+ Робота з негативними публікаціями та спростуваннями.\n+ Організація прес-конференцій та медіа-подій (за потреби).\n+ Підготовка матеріалів для гостьових публікацій.\n+ Щомісячна звітність з медіа-активності та охоплення.','\n',char(10)),'1-3 місяці для встановлення медіа-зв''язків','Бюджет на медіа-кіт та івенти','active','usr_admin_001','2026-02-24 19:25:03','2026-03-16 16:24:44',NULL);
INSERT INTO "pr_packages" ("id","number","name","description","teams_involved","requirements","goals","components_list","timeline","expenses","status","created_by","created_at","updated_at","used_in_brand_id") VALUES('prp_677aea62d5f342b9',5,'Brand Excellence','Управління участю бренду в нішевих iGaming-нагородах, конкурсах та спонсорських активностях — від відбору подій до підготовки документів та підтримки репутації.','PR, Retention, Creative','Інформація про бренд + досягнення компанії + бюджет на участь',replace('1. Підвищити впізнаваність бренду через участь у галузевих нагородах.\n2. Побудувати імідж інноваційної та відповідальної компанії.\n3. Отримати додаткові PR-приводи через нагороди та номінації.\n4. Зміцнити позиції бренду серед конкурентів через спонсорства.','\n',char(10)),replace('+ Аналіз релевантних iGaming-нагород та конкурсів для участі.\n+ Підготовка заявок та супровідних матеріалів для номінацій.\n+ Координація процесу подання на нагороди та відстеження результатів.\n+ Пошук спонсорських можливостей у профільних подіях.\n+ Підготовка презентаційних матеріалів для спонсорських активацій.\n+ PR-підтримка під час та після отримання нагород.\n+ Моніторинг репутаційного впливу участі в нагородах.\n+ Щомісячна звітність з аналізом ROI спонсорських активностей.','\n',char(10)),'3-6 місяців залежно від календаря подій','Реєстраційні внески та спонсорські пакети','active','usr_admin_001','2026-02-24 19:27:22','2026-03-16 16:25:47',NULL);
INSERT INTO "pr_packages" ("id","number","name","description","teams_involved","requirements","goals","components_list","timeline","expenses","status","created_by","created_at","updated_at","used_in_brand_id") VALUES('prp_11e7a0f3079a47c3',6,'Total Market Presence','Залучення інфлюєнсерів для проведення PR-активностей бренду — від пошуку релевантних амбасадорів до організації кампаній та аналізу результатів.','PR, Copy, SMM','Бриф кампанії + бюджет на інфлюєнсерів + креативні матеріали',replace('1. Підвищити охоплення цільової аудиторії через довірених лідерів думок.\n2. Сформувати позитивне сприйняття бренду через автентичні рекомендації.\n3. Залучити нових користувачів через інфлюєнсер-кампанії.\n4. Побудувати довгострокові відносини з ключовими амбасадорами бренду.','\n',char(10)),replace('+ Аналіз та відбір релевантних інфлюєнсерів для бренду.\n+ Розробка стратегії інфлюєнсер-маркетингу та кампаній.\n+ Переговори та укладання угод з обраними інфлюєнсерами.\n+ Підготовка брифів та креативних матеріалів для кампаній.\n+ Координація виробництва контенту разом з інфлюєнсерами.\n+ Моніторинг публікацій та взаємодії з аудиторією.\n+ Аналіз ефективності кампаній: охоплення, залученість, конверсії.\n+ Щомісячна звітність з рекомендаціями щодо оптимізації.','\n',char(10)),'2-4 місяці для запуску перших кампаній','Бюджет на гонорари інфлюєнсерів та продакшн','active','usr_admin_001','2026-02-24 19:29:23','2026-03-16 16:26:08',NULL);
